-- MailSender Database Schema
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE IF NOT EXISTS campaigns (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT NOT NULL, subject TEXT NOT NULL, source TEXT NOT NULL, template_id UUID, status TEXT NOT NULL DEFAULT 'draft' CHECK (status IN ('draft', 'scheduled', 'running', 'paused', 'completed', 'archived')), scheduled_at TIMESTAMPTZ, started_at TIMESTAMPTZ, completed_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS email_templates (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT NOT NULL UNIQUE, subject TEXT, content TEXT NOT NULL, is_active BOOLEAN DEFAULT true, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS contact_lists (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT NOT NULL, description TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS contacts (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), email TEXT NOT NULL, first_name TEXT, last_name TEXT, list_id UUID, status TEXT DEFAULT 'active' CHECK (status IN ('active', 'suppressed', 'suppressed complaint')), suppression_token TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(email, list_id));
CREATE TABLE IF NOT EXISTS contact_segments (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name TEXT NOT NULL, description TEXT, filter_rules JSONB DEFAULT '[]', created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS contact_segment_contacts (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), segment_id UUID REFERENCES contact_segments(id) ON DELETE CASCADE, contact_id UUID REFERENCES contacts(id) ON DELETE CASCADE, created_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(segment_id, contact_id));
CREATE TABLE IF NOT EXISTS contact_suppression (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), email TEXT NOT NULL UNIQUE, reason TEXT NOT NULL, source TEXT DEFAULT 'auto' CHECK (source IN ('auto', 'manual', 'ses', 'import')), created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS email_events (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), campaign_id UUID, contact_id UUID, email TEXT NOT NULL, message_id TEXT, event_type TEXT NOT NULL CHECK (event_type IN ('bounce', 'complaint', 'delivery', 'open', 'click')), bounce_type TEXT, bounce_sub_type TEXT, complaint_type TEXT, smtp_response TEXT, url TEXT, user_agent TEXT, ip_address TEXT, raw_event JSONB, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS campaign_stats (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), campaign_id UUID REFERENCES campaigns(id) UNIQUE, total_sent INTEGER DEFAULT 0, total_delivered INTEGER DEFAULT 0, total_opened INTEGER DEFAULT 0, total_clicked INTEGER DEFAULT 0, total_bounced INTEGER DEFAULT 0, total_complained INTEGER DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS email_jobs (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), campaign_id UUID REFERENCES campaigns(id) ON DELETE SET NULL, source TEXT NOT NULL, destinations TEXT[] NOT NULL, template_name TEXT NOT NULL, template_data JSONB, options JSONB, status TEXT DEFAULT 'pending' CHECK (status IN ('pending', 'sent', 'failed', 'suppressed')), error TEXT, retry_count INTEGER DEFAULT 0, retry_after TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), completed_at TIMESTAMPTZ);
ALTER TABLE campaigns ADD CONSTRAINT campaigns_template_id_fkey FOREIGN KEY (template_id) REFERENCES email_templates(id) ON DELETE SET NULL;
ALTER TABLE contacts ADD CONSTRAINT contacts_list_id_fkey FOREIGN KEY (list_id) REFERENCES contact_lists(id) ON DELETE SET NULL;
ALTER TABLE email_events ADD CONSTRAINT email_events_campaign_id_fkey FOREIGN KEY (campaign_id) REFERENCES campaigns(id) ON DELETE SET NULL;
ALTER TABLE email_events ADD CONSTRAINT email_events_contact_id_fkey FOREIGN KEY (contact_id) REFERENCES contacts(id) ON DELETE SET NULL;
ALTER TABLE campaign_stats ADD CONSTRAINT campaign_stats_campaign_id_fkey FOREIGN KEY (campaign_id) REFERENCES campaigns(id) ON DELETE CASCADE;
CREATE INDEX IF NOT EXISTS idx_email_events_email ON email_events(email);
CREATE INDEX IF NOT EXISTS idx_email_events_campaign_id ON email_events(campaign_id);
CREATE INDEX IF NOT EXISTS idx_email_events_contact_id ON email_events(contact_id);
CREATE INDEX IF NOT EXISTS idx_email_events_event_type ON email_events(event_type);
CREATE INDEX IF NOT EXISTS idx_email_events_created_at ON email_events(created_at);
CREATE INDEX IF NOT EXISTS idx_contacts_email ON contacts(email);
CREATE INDEX IF NOT EXISTS idx_contacts_list_id ON contacts(list_id);
CREATE INDEX IF NOT EXISTS idx_contact_suppression_email ON contact_suppression(email);
CREATE INDEX IF NOT EXISTS idx_campaigns_status ON campaigns(status);
CREATE INDEX IF NOT EXISTS idx_email_jobs_status ON email_jobs(status);
CREATE INDEX IF NOT EXISTS idx_email_jobs_created_at ON email_jobs(created_at);
CREATE OR REPLACE FUNCTION get_campaign_analytics(p_campaign_id UUID) RETURNS TABLE (campaign_id UUID, total_sent BIGINT, total_delivered BIGINT, total_opened BIGINT, total_clicked BIGINT, total_bounced BIGINT, total_complained BIGINT) AS $$ BEGIN RETURN QUERY SELECT c.id as campaign_id, COALESCE(ce.sent_count, 0) as total_sent, COALESCE((SELECT COUNT(*) FROM email_events ee WHERE ee.campaign_id = c.id AND ee.event_type = 'delivery'), 0) as total_delivered, COALESCE((SELECT COUNT(*) FROM email_events ee WHERE ee.campaign_id = c.id AND ee.event_type = 'open'), 0) as total_opened, COALESCE((SELECT COUNT(*) FROM email_events ee WHERE ee.campaign_id = c.id AND ee.event_type = 'click'), 0) as total_clicked, COALESCE((SELECT COUNT(*) FROM email_events ee WHERE ee.campaign_id = c.id AND ee.event_type = 'bounce'), 0) as total_bounced, COALESCE((SELECT COUNT(*) FROM email_events ee WHERE ee.campaign_id = c.id AND ee.event_type = 'complaint'), 0) as total_complained FROM campaigns c LEFT JOIN (SELECT campaign_id, COUNT(*) as sent_count FROM email_jobs WHERE status = 'sent' GROUP BY campaign_id) ce ON c.id = ce.campaign_id WHERE c.id = p_campaign_id; END; $$ LANGUAGE plpgsql;
